ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?summary WHERE {
  ?books a :Book .
  ?books p:Summary ?summary .
  ?books p:PublicationYear ?publicationyear_b .
  FILTER(?publicationyear_b >= 1800 && ?publicationyear_b <= 1899)
} }
  full: { SELECT ?summary ?themes WHERE {
  ?books a :Book .
  ?books p:Summary ?summary .
  ?books p:Themes ?themes .
  ?books p:PublicationYear ?publicationyear_b .
  FILTER(?publicationyear_b >= 1800 && ?publicationyear_b <= 1899)
} }
  component_2: { SELECT ?themes WHERE {
  ?books a :Book .
  ?books p:Themes ?themes .
  ?books p:PublicationYear ?publicationyear_b .
  FILTER(?publicationyear_b >= 1800 && ?publicationyear_b <= 1899)
} }
}

